import React from "react"

import Layout from "../components/layout"
import SEO from "../components/seo"
// Components
import Header from "../components/Header"
import Experience from "../components/Experience"
import About from "../components/About"
import Skills from "../components/skills"
import Footer from "../components/Footer"
import SelectedProjects from "../components/SelectedProjects"
import Cube from "../components/Cube"
import Towers from "../components/Towers"
import Publications from "../components/Publications"

const IndexPage = () => (
  <Layout>
    {/* eslint-disable-next-line react/jsx-pascal-case */}
    <SEO
      title="Julius Chen Portfolio"
      keywords={[
        "Julius Chen", "Civil Engineering", "Robotics", "Structural Design",
        "Portfolio", "Taiwan University", "University of Waterloo",
        "Orbital Simulator", "Wooden Truss Bridge Design", "Experience",
        "JavaScript Developer", "Gatsby React"
      ]}
    />
    <Header></Header>
    <About></About>
    <Cube></Cube>
    <Towers></Towers>
    <Publications></Publications>
    <Experience></Experience>
    <SelectedProjects></SelectedProjects>
    <Skills></Skills>
    <Footer></Footer>
  </Layout>
)

export default IndexPage
